from typing import List, Optional
import strawberry
from sqlalchemy.orm import sessionmaker, relationship
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey

# SQLAlchemy setup
Base = declarative_base()
engine = create_engine('sqlite:///:memory:')
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)

# Define models
class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    reviews = relationship("Review", back_populates="product")
    sellers = relationship("Seller", back_populates="products")
    categories = relationship("Category", secondary="product_category_association", back_populates="products")
    images = relationship("Image", back_populates="product")

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True, index=True)
    content = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="reviews")

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    products = relationship("Product", back_populates="sellers")

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)

product_category_association = Table(
    "product_category_association",
    Base.metadata,
    Column("product_id", Integer, ForeignKey('products.id')),
    Column("category_id", Integer, ForeignKey('categories.id'))
)

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True, index=True)
    url = Column(String, index=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("Product", back_populates="images")

# Create tables
Base.metadata.create_all(bind=engine)

# GraphQL schema
@strawberry.type
class ReviewType:
    id: int
    content: str

@strawberry.type
class SellerType:
    id: int
    name: str

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    url: str

@strawberry.type
class ProductType:
    id: int
    name: str
    reviews: List[ReviewType]
    sellers: List[SellerType]
    categories: List[CategoryType]
    images: List[ImageType]

@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> ProductType:
        session = SessionLocal()
        product = session.query(Product).get(id)
        return ProductType(
            id=product.id,
            name=product.name,
            reviews=[ReviewType(id=review.id, content=review.content) for review in product.reviews],
            sellers=[SellerType(id=seller.id, name=seller.name) for seller in product.sellers],
            categories=[CategoryType(id=category.id, name=category.name) for category in product.categories],
            images=[ImageType(id=image.id, url=image.url) for image in product.images]
        )

# Start the GraphQL server
schema = strawberry.Schema(query=Query)